async function closeActus() {
  const overlay = document.getElementById("actus-overlay");
  if (!overlay) return;

  const modal = overlay.querySelector(".actus-modal");
  if (modal) modal.classList.add("is-saving");

  // Désactive l'édition
  const fields = document.querySelectorAll("#actus-notes, [id^='actus-salle-']");
  fields.forEach(el => { if (el) el.contentEditable = "false"; });

  actusActiveEl = null;
  actusSavedRange = null;

  // ✅ laisse le temps au navigateur d'afficher le spinner AVANT le fetch
  await new Promise(requestAnimationFrame);

  try {
    await saveActusNow();
  } catch (e) {
    console.error("Erreur sauvegarde actus", e);
  } finally {
    if (modal) modal.classList.remove("is-saving");
    overlay.classList.remove("is-open");
  }
}


async function openActus() {
  ensureActusOverlay();

  const overlay = document.getElementById("actus-overlay");
  overlay.classList.add("is-open"); // ✅ ouvre tout de suite

  setActusLoading(true);

  // ✅ met le bon titre immédiatement
  updateActusBlocTitle();

  try {
    await maybeResetBlocAtNoon();
    await loadActusFromServer();

    // ✅ resécurise le titre après chargement/purge
    updateActusBlocTitle();
  } finally {
    setActusLoading(false);
    initActusInlineEditing();
  }
}


function setActusLoading(isLoading) {
  const modal = document.querySelector("#actus-overlay .actus-modal");
  if (!modal) return;

  modal.classList.toggle("is-loading", !!isLoading);

  // Désactive la toolbar pendant chargement (optionnel)
  const tools = modal.querySelectorAll(".actus-tool, .actus-color");
  tools.forEach(el => el.disabled = !!isLoading);

  // Empêche l’édition pendant chargement
  const fields = modal.querySelectorAll("#actus-notes, [id^='actus-salle-']");
  fields.forEach(el => {
    if (isLoading) el.setAttribute("contenteditable", "false");
  });
}


async function loadActusFromServer() {
  try {
    const res = await fetch(ACTUS_API_URL);
    const data = await res.json();

    document.getElementById("actus-notes").innerHTML = data.notes || "";

    [2,3,4,5,6,7].forEach(n => {
      const el = document.getElementById(`actus-salle-${n}`);
      if (el) el.innerHTML = data.bloc?.[n] || "";
    });
  } catch (e) {
    console.error("Erreur chargement actus", e);
  }
}

async function saveActusNow() {
  const payload = {
    notes: document.getElementById("actus-notes")?.innerHTML || "",
    bloc: {}
  };
  [2,3,4,5,6,7].forEach(n => {
    payload.bloc[n] = document.getElementById(`actus-salle-${n}`)?.innerHTML || "";
  });

  try {
    // ✅ form-urlencoded => évite le preflight CORS
    const body = new URLSearchParams();
    body.set("payload", JSON.stringify(payload));

    const res = await fetch(ACTUS_API_URL, {
      method: "POST",
      body
    });

    if (!res.ok) {
      const txt = await res.text();
      console.error("Erreur sauvegarde actus:", res.status, txt);
    }
  } catch (e) {
    console.error("Erreur sauvegarde actus", e);
  }
}


let actusActiveEl = null;
let actusSavedRange = null;

function actusSaveSelection() {
  const sel = window.getSelection();
  if (!sel || sel.rangeCount === 0) return;
  actusSavedRange = sel.getRangeAt(0).cloneRange();
}

function actusRestoreSelection() {
  if (!actusSavedRange) return;
  const sel = window.getSelection();
  if (!sel) return;
  sel.removeAllRanges();
  sel.addRange(actusSavedRange);
}

function actusCmd(cmd) {
  if (!actusActiveEl) return;

  actusActiveEl.focus();
  actusRestoreSelection();

  document.execCommand(cmd, false, null);
  saveActusNow();
}

function actusColor(color) {
  if (!actusActiveEl || !color) return;

  actusActiveEl.focus();
  actusRestoreSelection();

  document.execCommand("foreColor", false, color);
  saveActusNow();
}


function initActusInlineEditing() {
  const notes = document.getElementById("actus-notes");
  if (!notes) return;
  if (notes.dataset.inlineInit === "1") return;
  notes.dataset.inlineInit = "1";

  function wireSelectionSaving(el) {
    el.addEventListener("mouseup", actusSaveSelection);
    el.addEventListener("keyup", actusSaveSelection);
    el.addEventListener("pointerup", actusSaveSelection);
    el.addEventListener("touchend", actusSaveSelection);
  }

  function activate(el) {
    // désactive l'ancien champ si on en active un autre
    if (actusActiveEl && actusActiveEl !== el) {
      actusActiveEl.contentEditable = "false";
    }

    el.contentEditable = "true";
    el.focus();

    actusActiveEl = el;
    wireSelectionSaving(el);
    actusSaveSelection();
  }

  // Double-tap/clic universel (au lieu de dblclick)
  function onDoubleActivate(targetEl, cb) {
    let lastUp = 0, lastX = 0, lastY = 0;
    targetEl.addEventListener("pointerup", (e) => {
      const now = Date.now();
      const dt = now - lastUp;
      const dx = Math.abs(e.clientX - lastX);
      const dy = Math.abs(e.clientY - lastY);
      if (dt > 0 && dt < 450 && dx < 14 && dy < 14) {
        cb();
        lastUp = 0;
        return;
      }
      lastUp = now; lastX = e.clientX; lastY = e.clientY;
    });
  }

  // Notes
  const notesCard = notes.closest(".actus-card") || notes.parentElement;
  if (notesCard) onDoubleActivate(notesCard, () => activate(notes));

  notes.addEventListener("focus", () => {
    actusActiveEl = notes;
    actusSaveSelection();
  });
  wireSelectionSaving(notes);

  // Salles
  [2,3,4,5,6,7].forEach(n => {
    const el = document.getElementById(`actus-salle-${n}`);
    if (!el) return;

    const line = el.closest(".actus-salle-line") || el.parentElement;
    if (line) onDoubleActivate(line, () => activate(el));

    el.addEventListener("focus", () => {
      actusActiveEl = el;
      actusSaveSelection();
    });

    wireSelectionSaving(el);
  });

  // ✅ IMPORTANT :
  // - plus de blur => save
  // - plus de "clic ailleurs => blur"
  // => la sauvegarde se fait UNIQUEMENT dans closeActus()

  // ✅ Toolbar : empêche de perdre la sélection au clic
  const toolbar = document.querySelector("#actus-overlay .actus-toolbar");
  if (toolbar && toolbar.dataset.keepSel !== "1") {
    toolbar.dataset.keepSel = "1";
    toolbar.addEventListener("pointerdown", (e) => {
      e.preventDefault(); // garde la sélection active
    });
  }
  // Si tu veux : Escape = fermer (et donc sauvegarder)
  document.addEventListener("keydown", (e) => {
    if (e.key === "Escape") {
      const overlay = document.getElementById("actus-overlay");
      if (overlay && overlay.classList.contains("is-open")) closeActus();
    }
  }, { once: true });
}



function isAfterNoonNow() {
  const now = new Date();
  const noon = new Date(now);
  noon.setHours(12, 0, 0, 0);
  return now >= noon;
}

function getOrganisationDate() {
  const d = new Date();
  if (isAfterNoonNow()) d.setDate(d.getDate() + 1); // après 12:00 => demain
  return d;
}

function formatFRDate(d) {
  const dd = String(d.getDate()).padStart(2, "0");
  const mm = String(d.getMonth() + 1).padStart(2, "0");
  const yyyy = d.getFullYear();
  return `${dd}/${mm}/${yyyy}`;
}

function updateActusBlocTitle() {
  const el = document.getElementById("actus-bloc-title");
  if (!el) return;
  el.textContent = `Organisation bloc 3ème du ${formatFRDate(getOrganisationDate())}`;
}

// -------------------------------
//  Purge quotidienne à 12:00
// -------------------------------

function todayISO() {
  const d = new Date();
  return d.toISOString().slice(0, 10);
}
function isAfterNoonNow() {
  const now = new Date();
  return (now.getHours() > 12) || (now.getHours() === 12 && now.getMinutes() >= 0);
}
function resetBlocForTomorrow() {
  localStorage.removeItem(getBlocKeyForTomorrow());
}
// Version "sans serveur" : on reset uniquement en local
async function resetBlocForTomorrowServer() {
  resetBlocForTomorrow();
}

async function maybeResetBlocAtNoon() {
  const day = todayISO(); // ta fonction existante (YYYY-MM-DD)
  const last = localStorage.getItem(ACTUS_BLOC_LAST_RESET_KEY);

  // si on est après midi ET pas encore reset aujourd’hui => purge bloc serveur
  if (isAfterNoonNow() && last !== day) {
    await resetBlocForTomorrowServer(); // ta fonction existante (vide salles 2-7 sur le serveur)
    localStorage.setItem(ACTUS_BLOC_LAST_RESET_KEY, day);
  }

  // Dans tous les cas, on met à jour le titre selon l'heure
  updateActusBlocTitle();
}


function scheduleNoonReset() {
  const now = new Date();
  const target = new Date(now);
  target.setHours(12, 0, 0, 0);
  if (now >= target) target.setDate(target.getDate() + 1);

  const delay = target.getTime() - now.getTime();
  setTimeout(() => {
    maybeResetBlocAtNoon();
    scheduleNoonReset();
  }, delay);
}

// À appeler UNE FOIS au démarrage de l'app (PC)
function initActusNoonReset() {
  maybeResetBlocAtNoon();
  scheduleNoonReset();

  document.addEventListener("visibilitychange", () => {
    if (!document.hidden) maybeResetBlocAtNoon();
  });
}

function autoGrow(el){
  el.style.height = "auto";
  el.style.height = el.scrollHeight + "px";
}

// =======================================================
//  LOGO SARIC NEWS — draggable (PC + mobile) + position mémorisée
//  - Glisser-déposer souris/doigt
//  - Ne déclenche PAS openActus() si on a déplacé le logo
//  - Mémorise la position dans localStorage
// =======================================================

const SARIC_LOGO_POS_KEY = "saricnews_logo_pos_v1";

function clamp(v, min, max) {
  return Math.min(Math.max(v, min), max);
}

function restoreSaricLogoPosition(el) {
  try {
    const raw = localStorage.getItem(SARIC_LOGO_POS_KEY);
    if (!raw) return;

    const pos = JSON.parse(raw);
    if (typeof pos?.left !== "number" || typeof pos?.top !== "number") return;

    el.style.left = `${pos.left}px`;
    el.style.top = `${pos.top}px`;
    el.style.right = "auto";  // important: on quitte le mode top/right
    el.style.bottom = "auto";
  } catch (_) {}
}

function saveSaricLogoPosition(el) {
  const rect = el.getBoundingClientRect();
  localStorage.setItem(SARIC_LOGO_POS_KEY, JSON.stringify({
    left: Math.round(rect.left),
    top: Math.round(rect.top)
  }));
}

function initDraggableSaricLogo() {
  const el = document.getElementById("saricnews-logo");
  if (!el) return;

  // évite double init si renderHome est rappelé
  if (el.dataset.dragInit === "1") return;
  el.dataset.dragInit = "1";

  restoreSaricLogoPosition(el);

  let startX = 0, startY = 0;
  let startLeft = 0, startTop = 0;
  let dragging = false;

  // Empêche le clic (openActus) juste après un drag
  el.addEventListener("click", (e) => {
    if (el.dataset.justDragged === "1") {
      e.preventDefault();
      e.stopPropagation();
      e.stopImmediatePropagation();
      el.dataset.justDragged = "0";
    }
  }, true);

  el.addEventListener("pointerdown", (e) => {
    // uniquement bouton principal souris ou touch/stylus
    if (e.pointerType === "mouse" && e.button !== 0) return;

    const rect = el.getBoundingClientRect();

    startX = e.clientX;
    startY = e.clientY;
    startLeft = rect.left;
    startTop = rect.top;
    dragging = false;

    // bascule en mode left/top pour drag
    el.style.left = `${startLeft}px`;
    el.style.top = `${startTop}px`;
    el.style.right = "auto";
    el.style.bottom = "auto";

    el.setPointerCapture(e.pointerId);
  });

  el.addEventListener("pointermove", (e) => {
    if (!el.hasPointerCapture(e.pointerId)) return;

    const dx = e.clientX - startX;
    const dy = e.clientY - startY;

    // seuil : si on bouge un peu, on considère que c'est un drag
    if (!dragging && (Math.abs(dx) > 4 || Math.abs(dy) > 4)) {
      dragging = true;
    }
    if (!dragging) return;

    const w = el.offsetWidth;
    const h = el.offsetHeight;

    const maxLeft = window.innerWidth - w;
    const maxTop  = window.innerHeight - h;

    const newLeft = clamp(startLeft + dx, 0, Math.max(0, maxLeft));
    const newTop  = clamp(startTop + dy, 0, Math.max(0, maxTop));

    el.style.left = `${newLeft}px`;
    el.style.top = `${newTop}px`;
  });

  el.addEventListener("pointerup", (e) => {
    if (!el.hasPointerCapture(e.pointerId)) return;
    el.releasePointerCapture(e.pointerId);

    if (dragging) {
      saveSaricLogoPosition(el);
      el.dataset.justDragged = "1";
      // remet à 0 après un court délai pour éviter blocage de clic
      setTimeout(() => { el.dataset.justDragged = "0"; }, 250);
    }
  });

  // Si l'écran change (rotation / redimensionnement), on re-clamp la position
  window.addEventListener("resize", () => {
    const rect = el.getBoundingClientRect();
    const w = el.offsetWidth, h = el.offsetHeight;
    const maxLeft = window.innerWidth - w;
    const maxTop  = window.innerHeight - h;

    const newLeft = clamp(rect.left, 0, Math.max(0, maxLeft));
    const newTop  = clamp(rect.top, 0, Math.max(0, maxTop));

    el.style.left = `${newLeft}px`;
    el.style.top = `${newTop}px`;
    el.style.right = "auto";
    el.style.bottom = "auto";

    saveSaricLogoPosition(el);
  });
}


