// Toggle des sous-listes (lignes bleues)
function toggleEtoSub(id) {
  const el = document.getElementById(id);
  if (!el) return;
  const visible = window.getComputedStyle(el).display !== "none";
  el.style.display = visible ? "none" : "block";
}


