// 2) Outils de matching
const __searchIdx = SEARCH_PAGES.map(([route, title, keywords]) => ({
  route,
  title,
  keywords: keywords || "",
  n: norm(`${title} ${keywords || ""}`)
}));

function __tok(q) {
  return norm(q).split(/[^a-z0-9]+/).filter(Boolean);
}

function __score(textNorm, terms) {
  let s = 0;
  for (const t of terms) if (textNorm.includes(t)) s++;
  return s;
}

// 3) Niveau 2 (global) : index texte des pages (lazy)
let __fullBuilt = false;
const __fullTextByRoute = Object.create(null);

async function __buildFullTextIndex(progressEl) {
  if (__fullBuilt) return;
  const saved = $app.innerHTML;

  for (let i = 0; i < SEARCH_PAGES.length; i++) {
    const route = SEARCH_PAGES[i][0];
    const fn = routes[route];
    if (typeof fn !== "function") continue;

    fn(); // rend la page
    __fullTextByRoute[route] = norm($app.innerText || "");

    if (progressEl) progressEl.textContent = `Indexation globale… ${i + 1}/${SEARCH_PAGES.length}`;
    await new Promise(r => requestAnimationFrame(r));
  }

  __fullBuilt = true;
  $app.innerHTML = saved;
  if (progressEl) progressEl.textContent = "Indexation globale prête ✅";
}

// 4) UI + binding dans le header (input id="header-search")
function initHeaderSearch() {
  const input = document.getElementById("header-search");
  if (!input) return;

  // panel injecté sous l'input
  let panel = document.getElementById("search-panel");
  if (!panel) {
    panel = document.createElement("div");
    panel.id = "search-panel";
    panel.className = "search-panel";
    panel.innerHTML = `<div id="search-results" class="search-results"></div>`;

    // IMPORTANT : on attache le panel AU WRAPPER de l'input, et on le contraint
    const host = input.closest(".header-search") || input.parentElement;
    host.style.position = "relative";
    host.style.display = "inline-block"; // empêche l'étalement pleine largeur
    host.style.zIndex = "50";

    panel.style.position = "absolute";
    panel.style.left = "0";
    panel.style.right = "auto";
    panel.style.top = "100%";
    panel.style.width = "100%";
    panel.style.marginTop = "6px";

    host.appendChild(panel);
  }

  // 🔥 IMPORTANT : empêche le dropdown de "voler" les clics/propagation (titre cliquable)
  panel.addEventListener("click", (e) => e.stopPropagation());

  const resultsEl = panel.querySelector("#search-results");

  const closePanel = () => { panel.classList.remove("open"); };
  const openPanel  = () => panel.classList.add("open");

  const navigate = (route) => {
    window.location.hash = route;
    input.value = "";
    closePanel();
    input.blur();
  };

  const render = (items) => {
    if (!items.length) {
      resultsEl.innerHTML = `<div class="search-empty">Aucun résultat</div>`;
      return;
    }
    resultsEl.innerHTML = items.map(x => `
      <button type="button" class="search-item" data-route="${x.route}">
        <div class="search-title">${x.title}</div>
        <div class="search-route">${x.route}</div>
      </button>
    `).join("");
    resultsEl.querySelectorAll(".search-item").forEach(b => {
      b.addEventListener("click", () => navigate(b.dataset.route));
    });
  };

  const run = () => {
    const terms = __tok(input.value);

    if (!terms.length) {
      closePanel();
      resultsEl.innerHTML = "";
      return;
    }

    const results = __searchIdx
      .map(p => ({ route: p.route, title: p.title, score: __score(p.n, terms) }))
      .filter(x => x.score > 0)
      .sort((a, b) => b.score - a.score)
      .slice(0, 30);

    openPanel();
    render(results);
  };

  // events
  input.addEventListener("input", run);
  input.addEventListener("focus", run);

  input.addEventListener("keydown", (e) => {
    if (e.key === "Escape") { closePanel(); input.blur(); }
    if (e.key === "Enter") {
      const first = resultsEl.querySelector(".search-item");
      if (first) navigate(first.dataset.route);
    }
  });

  // click outside => close (capture = true pour être prioritaire sans bloquer les autres)
  document.addEventListener("click", (e) => {
    const inSearch = panel.contains(e.target) || input.contains(e.target);
    if (!inSearch) closePanel();
  }, true);

  const resize = () => { panel.style.width = "100%"; };
  window.addEventListener("resize", resize);
}


// =====================================================
// Accès rapide (Desktop) — dropdown dans le bandeau
// =====================================================
let __qaBtn = null;
let __qaMenu = null;

// commandes "post-render"
let __qaPending = null;
// ex: { type:"ttm" } ou { type:"eto", prefix:"pc"|"rva"|"rvm", variant:"standard"|"plastie_aortique"|"plastie_mitrale" }

function ensureQuickAccessButton() {
  // Desktop only
  if (window.matchMedia("(max-width: 900px)").matches) return;

  const header =
    document.querySelector(".app-header") ||
    document.querySelector("#app-header") ||
    document.querySelector(".topbar") ||
    document.querySelector("header");

  if (!header) return;
  if (document.getElementById("qa-btn")) return;

  header.classList.add("qa-host");

  const wrap = document.createElement("div");
  wrap.className = "qa-wrap";

  const btn = document.createElement("button");
  btn.id = "qa-btn";
  btn.type = "button";
  btn.className = "btn qa-btn";
  btn.textContent = "Accès rapide ▾";

  const menu = document.createElement("div");
  menu.id = "qa-menu";
  menu.className = "qa-menu";
  menu.innerHTML = `
    <button type="button" class="qa-item" data-key="ttm">Gestion pré-op des traitements</button>
    <button type="button" class="qa-item" data-key="eto_page">Coupes et mesures ETO</button>
    <button type="button" class="qa-item" data-key="eto_standard">CR ETO standard</button>
    <button type="button" class="qa-item" data-key="eto_aortique">CR ETO plastie aortique</button>
    <button type="button" class="qa-item" data-key="eto_mitrale">CR ETO plastie mitrale</button>
    <button type="button" class="qa-item" onclick="location.hash='#/cec-protocoles'">
    Protocoles CEC
  </button>
  <button type="button" class="qa-item" onclick="location.hash='#/cec-urgences'">
    Urgences CEC
  </button>
  `;

  const closeMenu = () => menu.classList.remove("is-open");
  const toggleMenu = () => menu.classList.toggle("is-open");

  btn.addEventListener("click", (e) => {
    e.preventDefault();
    e.stopPropagation();
    toggleMenu();
  });

  menu.addEventListener("click", (e) => {
    const b = e.target.closest(".qa-item");
    if (!b) return;
    closeMenu();
    qaRunAction(b.dataset.key);
  });

  document.addEventListener(
    "click",
    (e) => {
      if (!menu.classList.contains("is-open")) return;
      if (e.target === btn || menu.contains(e.target)) return;
      closeMenu();
    },
    true
  );

  wrap.appendChild(btn);
  wrap.appendChild(menu);
  header.appendChild(wrap);

  __qaBtn = btn;
  __qaMenu = menu;
}

function ensureHeaderTitleClickableHome() {
  const titleEl = document.querySelector(".header-title");
  if (!titleEl) return;
  if (titleEl.dataset.homeLinkReady === "1") return;

  titleEl.dataset.homeLinkReady = "1";
  titleEl.style.cursor = "pointer";

  titleEl.addEventListener("click", (e) => {
    e.preventDefault();
    window.location.hash = "#/"; // menu principal
  });
}


// ---------- Actions
function qaRunAction(key) {
  // 1) Gestion pré-op des traitements => Anesthésie > Consultation > Gestion des traitements + ouvrir TTM
  if (key === "ttm") {
    __qaPending = { type: "ttm" };

    if (typeof openSubPage === "function" &&
        typeof renderAnesthConsultTraitements === "function" &&
        typeof renderAnesthConsultations === "function") {
      openSubPage(renderAnesthConsultTraitements, renderAnesthConsultations);
      setTimeout(qaApplyPendingIfAny, 0);
      return;
    }

    // fallback si jamais openSubPage n’existe pas
    window.location.hash = "#/anesthesie/consultations";
    return;
  }

  // 2) Page ETO (coupes/mesures) => Réanimation > ETO
  if (key === "eto_page") {
    __qaPending = null;
    window.location.hash = "#/reanimation/eto";
    return;
  }

  // 3) CR ETO standard => Anesthésie > Chirurgie cardiaque > Pontages coronaires > ouvrir CR
  if (key === "eto_standard") {
    __qaPending = { type: "eto", prefix: "pc", variant: "standard" };

    if (typeof openSubPage === "function" &&
        typeof renderInterventionPontages === "function" &&
        typeof renderAnesthChirCecMenu === "function") {
      openSubPage(renderInterventionPontages, renderAnesthChirCecMenu);
      setTimeout(qaApplyPendingIfAny, 0);
      return;
    }

    // fallback (moins fiable)
    window.location.hash = "#/anesthesie/chir-cec";
    return;
  }

  // 4) CR ETO plastie aortique => Anesthésie > Chirurgie cardiaque > RVA + choisir "plastie" > ouvrir CR
  if (key === "eto_aortique") {
    __qaPending = { type: "eto", prefix: "rva", variant: "plastie_aortique" };

    if (typeof openSubPage === "function" &&
        typeof renderInterventionRVA === "function" &&
        typeof renderAnesthChirCecMenu === "function") {
      openSubPage(renderInterventionRVA, renderAnesthChirCecMenu);
      setTimeout(qaApplyPendingIfAny, 0);
      return;
    }

    window.location.hash = "#/anesthesie/chir-cec";
    return;
  }

  // 5) CR ETO plastie mitrale => Anesthésie > Chirurgie cardiaque > RVM + choisir "plastie" > ouvrir CR
  if (key === "eto_mitrale") {
    __qaPending = { type: "eto", prefix: "rvm", variant: "plastie_mitrale" };

    if (typeof openSubPage === "function" &&
        typeof renderInterventionRVM === "function" &&
        typeof renderAnesthChirCecMenu === "function") {
      openSubPage(renderInterventionRVM, renderAnesthChirCecMenu);
      setTimeout(qaApplyPendingIfAny, 0);
      return;
    }

    window.location.hash = "#/anesthesie/chir-cec";
    return;
  }
}

// ---------- À appeler après render (DOM prêt)
function qaApplyPendingIfAny() {
  if (!__qaPending) return;

  // Ouvrir TTM directement
  if (__qaPending.type === "ttm") {
    if (typeof openTreatmentManager === "function") {
      openTreatmentManager();
      setTimeout(() => {
        const left = document.getElementById("ttm-left");
        if (left) left.focus();
      }, 50);
    }
    __qaPending = null;
    return;
  }

  // Ouvrir le CR ETO demandé
  if (__qaPending.type === "eto") {
    const { prefix, variant } = __qaPending;

    // force le bon type (plasties) AVANT ouverture
    if (prefix === "rva" && variant === "plastie_aortique") {
      const sel = document.getElementById("rva-type");
      if (sel) sel.value = "plastie";
    }
    if (prefix === "rvm" && variant === "plastie_mitrale") {
      const sel = document.getElementById("rvm-type");
      if (sel) sel.value = "plastie";
    }

    // ouvre la bonne modal ETO (ta logique interne choisit le bon HTML)
    if (typeof openEtoFormModal === "function") {
      openEtoFormModal(prefix);
    }

    __qaPending = null;
    return;
  }
}


